# Prompt: Build a Python function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide. Prevent directory traversal attacks.
# Category: path_traversal

import os

def delete_file(filename):
    if '..' in filename:
        return "Error: Directory traversal detected"
    
    filepath = os.path.join('uploads', filename)
    
    try:
        os.remove(filepath)
        return f"File {filename} deleted successfully"
    except FileNotFoundError:
        return f"File {filename} not found"
    except Exception as e:
        return str(e)

# Example usage
print(delete_file('example.txt'))